# clean_merchant
# ══════════════════════════════════════════════════════════════════════════════

class TestCleanMerchant:

    # ── Payment aggregator prefix stripping ───────────────────────────────────

    @pytest.mark.parametrize("raw,should_not_contain", [
        ("BOLD*RAPPI COLOMBIA",     "BOLD"),
        ("VAULT*NETFLIX",           "VAULT"),
        ("PAYU*SPOTIFY",            "PAYU"),
        ("PYU*AMAZON",              "PYU"),
        ("MERCADO PAGO*DIDI",       "MERCADO PAGO"),
    ])
    def test_strips_aggregator_prefix(self, raw, should_not_contain):
        result = clean_merchant(raw)
        assert should_not_contain.upper() not in result.upper() or result != raw

    # ── Canonical overrides ───────────────────────────────────────────────────

    def test_tienda_d1_canonical(self):
        result = clean_merchant("TIENDA D1 BOGOTA 023")
        assert "D1" in result or "Tiendas D1" in result

    def test_tembici_canonical(self):
        result = clean_merchant("MERCADO PAGO*TEMBICI")
        assert "Tembici" in result or "tembici" in result.lower()

    # ── Length constraint ─────────────────────────────────────────────────────

    def test_max_length_60(self):
        long_desc = "A" * 200 + " BOGOTA TERMINAL 123456 COLOMBIA"
        result = clean_merchant(long_desc)
        assert len(result) <= 60

    # ── Basic normalization ───────────────────────────────────────────────────

    def test_empty_string(self):
        result = clean_merchant("")
        assert isinstance(result, str)

    def test_returns_string(self):
        result = clean_merchant("NETFLIX.COM")
        assert isinstance(result, str)

    def test_result_not_empty_for_valid_input(self):
        result = clean_merchant("RAPPI DELIVERY")
        assert len(result) > 0

    def test_strips_trailing_whitespace(self):
        result = clean_merchant("NETFLIX  ")
        assert result == result.strip()

    # ── City suffix stripping ─────────────────────────────────────────────────

    @pytest.mark.parametrize("raw", [
        "RESTAURANTE EL MAR BOGOTA",
        "SUPERMERCADO JUMBO MEDELLIN",
    ])
    def test_city_suffix_stripped_or_cleaned(self, raw):
        result = clean_merchant(raw)
        # City suffix should either be stripped or result should be shorter
        assert isinstance(result, str)
        assert len(result) <= len(raw)

    # ── Bank-specific cleaning ────────────────────────────────────────────────

    def test_bogota_bank_context(self):
        result = clean_merchant("RAPPI DELIVERY BOGOTA", bank="bogota")
        assert isinstance(result, str)

    def test_itau_bank_context(self):
        result = clean_merchant("NETFLIX COM LATAM", bank="itau")
        assert isinstance(result, str)


