# normalize_brand
# ══════════════════════════════════════════════════════════════════════════════

class TestNormalizeBrand:

    @pytest.mark.parametrize("raw,expected", [
        # Delivery
        ("Rappi Colombia",       "Rappi"),
        ("RAPPI*DELIVERY",       "Rappi"),
        ("rappi",                "Rappi"),
        # Streaming
        ("NETFLIX.COM",          "Netflix"),
        ("Netflix",              "Netflix"),
        ("SPOTIFY AB",           "Spotify"),
        ("spotify",              "Spotify"),
        ("YOUTUBE PREMIUM",      "YouTube"),
        # Transport
        ("UBER* TRIP",           "Uber"),
        ("uber",                 "Uber"),
        ("DIDI TRANSPORT",       "DiDi"),
        # Food (iFood not in brand map)
        # Retail
        ("AMAZON.COM",           "Amazon"),
        ("MERCADO LIBRE",        "MercadoLibre"),   # no space in canonical
        # Supermarkets
        ("EXITO",                "Éxito"),
        # Tech
        ("APPLE.COM",            "Apple"),
        ("GOOGLE*PLAY",          "Google"),
        # Unknown brand is returned as-is (normalized case)
        ("ZAPATERIA RODRIGUEZ",  "ZAPATERIA RODRIGUEZ"),
    ])
    def test_brand_mapping(self, raw, expected):
        result = normalize_brand(raw)
        assert result == expected

    def test_returns_string(self):
        assert isinstance(normalize_brand("RAPPI"), str)

    def test_empty_string(self):
        result = normalize_brand("")
        assert isinstance(result, str)

    def test_case_insensitive(self):
        assert normalize_brand("netflix") == normalize_brand("NETFLIX")


