# build_brand_filter_list
# ══════════════════════════════════════════════════════════════════════════════

class TestBuildBrandFilterList:

    def test_deduplicates(self):
        merchants = ["RAPPI", "Rappi", "rappi", "NETFLIX", "Netflix"]
        result = build_brand_filter_list(merchants)
        # Should collapse variations into one canonical brand
        rappi_count = sum(1 for r in result if "rappi" in r.lower())
        assert rappi_count == 1

    def test_returns_list(self):
        result = build_brand_filter_list(["NETFLIX", "SPOTIFY"])
        assert isinstance(result, list)

    def test_empty_input(self):
        result = build_brand_filter_list([])
        assert result == []

    def test_preserves_unknown_brands(self):
        result = build_brand_filter_list(["UNKNOWN_SHOP_XYZ"])
        assert len(result) >= 1

    def test_sorted_or_consistent_order(self):
        merchants = ["SPOTIFY", "NETFLIX", "RAPPI"]
        result = build_brand_filter_list(merchants)
        assert len(result) > 0  # ordering may vary by impl

    def test_all_items_are_strings(self):
        result = build_brand_filter_list(["RAPPI", "NETFLIX", "UBER"])
        assert all(isinstance(r, str) for r in result)
